import{_ as e,p as i,q as l,a1 as a}from"./framework-e0dd9823.js";const c={},o=a('<h1 id="bfc-属性" tabindex="-1"><a class="header-anchor" href="#bfc-属性" aria-hidden="true">#</a> BFC 属性</h1><p>BFC(Block formatting context)直译为&quot;块级格式化上下文&quot;。 BFC 它是指一个独立的块级渲染区域，只有 Block-level BOX 参与，该区域拥有一套渲染规则来约束块级盒子的布局，且与区域外部无关。</p><h4 id="如何生成-bfc" tabindex="-1"><a class="header-anchor" href="#如何生成-bfc" aria-hidden="true">#</a> 如何生成 BFC</h4><ul><li>根元素</li><li>设置了一下属性的元素 <code>display:inline-block;</code><code>float:left | right;</code><code>overflow:hidden | auto | scroll;</code><code>position:absolute | fixed;</code></li></ul><h4 id="bfc-属性特性" tabindex="-1"><a class="header-anchor" href="#bfc-属性特性" aria-hidden="true">#</a> BFC 属性特性</h4><ol><li>内部的标签会在垂直方向上一个接一个的放置</li><li>垂直方向上的距离由 margin 决定，属于同一个 BFC 的两个相邻标签的 margin 会发生重叠</li><li>每个标签的左外边距与包含块的左边界相接触（从左向右），即使浮动标签也是如此。</li><li>BFC 的区域不会与 float 的标签区域重叠</li><li>计算 BFC 的高度时，浮动子标签也参与计算</li><li>BFC 就是页面上的一个隔离的独立容器，容器里面的子标签不会影响到外面标签，反之亦然</li></ol><h4 id="bfc-应用" tabindex="-1"><a class="header-anchor" href="#bfc-应用" aria-hidden="true">#</a> BFC 应用</h4><ul><li>margin 塌陷和合并问题</li><li>自适应布局问题</li><li>防止文字环绕</li><li>清除浮动</li></ul>',8),t=[o];function d(r,n){return i(),l("div",null,t)}const s=e(c,[["render",d],["__file","css-BFC.html.vue"]]);export{s as default};
